const GITLAB_GRAPHQL_URL = 'https://project.comsatel.com.pe/api/graphql';
const PERSONAL_ACCESS_TOKEN = 'gGsf6Sx-AF8nYo8Xahpi';

// 1. Definir los IDs numéricos de tus proyectos
const IDs_PROYECTOS = [1234, 5678, 9012];

// 2. Calcular la fecha de hace exactamente 1 hora en formato ISO
const unaHoraAtras = new Date(Date.now() - 60 * 60 * 1000).toISOString();

// 3. Función para obtener los issues de UN proyecto específico
async function obtenerIssuesDeProyecto(idNumerico) {
  // Convertir el ID numérico al formato Global ID que exige GitLab
  const globalProjectId = `gid://GitLab/Project/${idNumerico}`;

  const query = `
    query ($projectPath: ID!, $updatedAfter: Time!) {
    project(fullPath: $projectPath) {
      id
      name
      issues(updatedAfter: $updatedAfter) {
        nodes {
          iid
          title
          state
          updatedAt
          webUrl
          author {
            username
          }
        }
      }
    }
  }
  `;

  const variables = {
    projectId: globalProjectId,
    updatedAfter: unaHoraAtras
  };

  try {
    const response = await fetch(GITLAB_GRAPHQL_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${PERSONAL_ACCESS_TOKEN}`
      },
      body: JSON.stringify({ query, variables })
    });

    if (!response.ok) {
      throw new Error(`Error HTTP: ${response.status}`);
    }

    const resultado = await response.json();

    if (resultado.errors) {
      console.error(`Errores en proyecto ${idNumerico}:`, resultado.errors);
      return null;
    }

    // Retornamos los datos estructurados del proyecto y sus issues
    return resultado.data.node;

  } catch (error) {
    console.error(`Error de conexión en proyecto ${idNumerico}:`, error.message);
    return null;
  }
}

// 4. Función principal para procesar todos los proyectos en paralelo
async function obtenerTodosLosIssues() {
  console.log(`Buscando issues actualizados desde: ${unaHoraAtras}`);

  // Mapeamos el array de IDs a promesas y las ejecutamos en paralelo
  const promesas = IDs_PROYECTOS.map(id => obtenerIssuesDeProyecto(id));
  const resultados = await Promise.all(promesas);

  // Procesar y mostrar los resultados consolidados
  resultados.forEach((proyecto) => {
    if (!proyecto) return;

    console.log(`\n📦 Proyecto: ${proyecto.name} (ID: ${proyecto.id})`);
    const issues = proyecto.issues.nodes;

    if (issues.length === 0) {
      console.log('   ➔ Sin issues actualizados en la última hora.');
    } else {
      issues.forEach(issue => {
        console.log(`   #${issue.iid} - [${issue.state.toUpperCase()}] ${issue.title}`);
        console.log(`   Modificado: ${issue.updatedAt} por @${issue.author.username}`);
        console.log(`   Link: ${issue.webUrl}\n`);
      });
    }
  });
}

export default async function (ctx) {
  const { payload } = ctx;
  console.log("Procesando datos en JS...");

  const result = await obtenerTodosLosIssues([65]);

  return result;
}

export default async function (ctx) {
  const { payload } = ctx;

  // Función que genera la promesa de espera
  const esperarAleatorio = (min, max) => {
    // Genera segundos entre min y max, luego los pasa a milisegundos
    const milisegundos = Math.floor(Math.random() * (max - min + 1) + min) * 1000;
    console.log(`Esperando por ${milisegundos / 1000} segundos...`);
    return new Promise(resolve => setTimeout(resolve, milisegundos));
  };

  console.log('Procesando datos...');

  // Pausa aquí entre 10 y 40 segundos
  await esperarAleatorio(5, 10);

  return { ...payload, processed: true };
}
